export const continents = ["All", "Asia", "Europe", "Americas", "Africa", "Oceania"];

export const getFlagUrl = (code, size = 320) =>
  `https://flagcdn.com/w${size}/${code}.png`;

export const getRandomFlags = (count, exclude = [], difficulty = null) => {
  let pool = flags.filter(f => !exclude.includes(f.code));
  if (difficulty) pool = pool.filter(f => f.difficulty <= difficulty);
  const shuffled = [...pool].sort(() => Math.random() - 0.5);
  return shuffled.slice(0, count);
};

export const getByContinent = (continent) => {
  if (continent === "All") return flags;
  return flags.filter(f => f.continent === continent);
};

export const getFlagsWithAnimals = () => flags.filter(f => f.animal);

export const getSimilarFlags = (code) => {
  const flag = flags.find(f => f.code === code);
  if (!flag || !flag.similarTo.length) return [];
  return flag.similarTo.map(name => flags.find(f => f.name === name)).filter(Boolean);
};

export default flags;
